LAYER
	NAME "manantes"
	GROUP "PY148"
	MAXSCALE -1.0
	MINSCALE -1.0
	TYPE point
	PROCESSING "LABEL_NO_CLIP=1"
	PROCESSING "CLOSE_CONNECTION=DEFER"
	DUMP true
	HEADER "plantillas/inicio.html"
	#TEMPLATE "plantillas/uac/py148/manantes.html"
	FOOTER "plantillas/fin.html"
	STATUS on
	TRANSPARENCY 100
	DATA "geom FROM (SELECT gid, nombre_del, utm_altitu :: integer, tipo_de_us, tipo_de_af, ROUND(caudal__l_,2) AS caudal, nom_dist, comunidad, sector, geom FROM py148.manantes) as uac using unique gid using srid=32719"
	INCLUDE "configuracion/postgresql_uac.map"
	PROJECTION
		"init=epsg:32719"
	END
	CLASSITEM "gid"
	METADATA
		"wms_group_title" "PY148"
		"queryable" "true"
		"wms_metadataurl_href" ""
		"wms_metadataurl_format" "text/xml"
		"wms_metadataurl_type" "TC211"
		"wms_title" "Manantes"
		"wms_abstract" "Manantes || Universidad Andina del Cusco :: Perú"
		"wms_credit" "UAC"
		"wms_dataurl" ""
		"wms_dataurl_format" "text/html"
		"wms_dataurl_href" ""
		"autor" "UAC - 2022"
		"wms_extent" "153551.46779832867 8485032.000033027 203888.00001184182 8519351.999967571"
		"wms_srs" "EPSG:32719"
		"wms_include_items" "all"
		"wms_exclude_items" "gid"
		"wms_enable_request" "*"
	END
	CLASS
		NAME "Manantes"
		EXPRESSION /./
		STYLE
			SYMBOL "circulo"
			SIZE 3
			COLOR 255 255 0
			OUTLINECOLOR 0 0 0
		END #STYLE
		STYLE
			GEOMTRANSFORM "labelcenter"
			COLOR 153 153 153
		END # STYLE
		STYLE
			GEOMTRANSFORM "labelpoly"
			COLOR 255 0 0
		END # STYLE
	END
END # Layer